UPDATE `food-system`.dish
SET stock = stock - #{qty}
WHERE id = #{id}
  AND stock >= #{qty};

UPDATE `food-system`.dish
SET stock = stock + #{qty}
WHERE id = #{id};

UPDATE `food-system`.dish
SET locked_stock = dish.locked_stock - #{qty}
WHERE id = #{id};
